mapper.select:
SELECT id, rule_code, rule_name, sort_order, is_active
FROM series_priority_rule
WHERE id = #{id}

mapper.update:
UPDATE series_priority_rule SET updated_at = CURRENT_TIMESTAMP
    , rule_name = #{ruleName}
    , sort_order = #{sortOrder}
    , is_active = #{isActive}
WHERE id = #{id}
